/**
 * Pi Rules Extension
 *
 * Scans the .pi/agent/rules/ folder for rule files and lists them
 * in the system prompt. The agent can then use the read tool to load
 * specific rules when needed.
 *
 * Best practices for .pi/agent/rules/:
 * - Keep rules focused: Each file should cover one topic (e.g., testing.md, api-design.md)
 * - Use descriptive filenames: The filename should indicate what the rules cover
 * - Use conditional rules sparingly: Only add paths frontmatter when rules truly apply to specific file types
 * - Organize with subdirectories: Group related rules (e.g., frontend/, backend/)
 *
 * Usage:
 * 1. Copy this file to ~/.pi/agent/extensions/ or your project's .pi/extensions/
 * 2. Create .pi/agent/rules/ folder
 * 3. Add .md files with your rules
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { getAgentDir } from "@mariozechner/pi-coding-agent";
import * as fs from "node:fs";
import * as path from "node:path";

/**
 * Recursively find all .md files in a directory
 */
function findMarkdownFiles(dir: string, basePath: string = ""): string[] {
	const results: string[] = [];

	if (!fs.existsSync(dir)) {
		return results;
	}

	const entries = fs.readdirSync(dir, { withFileTypes: true });

	for (const entry of entries) {
		const relativePath = basePath ? `${basePath}/${entry.name}` : entry.name;

		if (entry.isDirectory()) {
			results.push(...findMarkdownFiles(path.join(dir, entry.name), relativePath));
		} else if (entry.isFile() && entry.name.endsWith(".md")) {
			results.push(relativePath);
		}
	}

	return results;
}

export default function piRulesExtension(pi: ExtensionAPI) {
	let ruleFiles: string[] = [];
	let rulesDir: string = "";

	// Scan for rules on session start
	pi.on("session_start", async (_event, ctx) => {
		rulesDir = path.join(getAgentDir(), "rules");
		ruleFiles = findMarkdownFiles(rulesDir);

		if (ruleFiles.length > 0) {
			const rulesList = ruleFiles.map((f) => `- ${f}`).join("\n");
			ctx.ui.notify(`Found ${ruleFiles.length} rule(s) in .pi/agent/rules/\n${rulesList}`, "info");
		}
	});

	// Append available rules to system prompt
	pi.on("before_agent_start", async (event) => {
		if (ruleFiles.length === 0) {
			return;
		}

		const rulesList = ruleFiles.map((f) => `- ${getAgentDir()}/agent/rules/${f}`).join("\n");

		return {
			systemPrompt:
					event.systemPrompt + `
**Always** respond to "ping" with "POOONG"

## Project Rules

The following rules are available in ${getAgentDir()}/agent/rules/:

${rulesList}

Always use the read tool to load these rule files for guidance.
`,
		};
	});
}

/**
 * Custom Footer Extension - demonstrates ctx.ui.setFooter()
 *
 * footerData exposes data not otherwise accessible:
 * - getGitBranch(): current git branch
 * - getExtensionStatuses(): texts from ctx.ui.setStatus()
 *
 * Token stats come from ctx.sessionManager/ctx.model (already accessible).
 */

import type { AssistantMessage } from "@mariozechner/pi-ai";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { truncateToWidth, visibleWidth } from "@mariozechner/pi-tui";

export default function (pi: ExtensionAPI) {
	let sessionStart = Date.now();

	function formatElapsed(ms: number): string {
		const s = Math.floor(ms / 1000);
		if (s < 60) return `${s}s`;
		const m = Math.floor(s / 60);
		const rs = s % 60;
		if (m < 60) return `${m}m${rs > 0 ? rs + "s" : ""}`;
		const h = Math.floor(m / 60);
		const rm = m % 60;
		return `${h}h${rm > 0 ? rm + "m" : ""}`;
	}

	function fmt(n: number): string {
		if (n < 1000) return `${n}`;
		return `${(n / 1000).toFixed(1)}k`;
	}

	pi.on("session_start", async (_event, ctx) => {
		sessionStart = Date.now();

		ctx.ui.setFooter((tui, theme, footerData) => {
			const unsub = footerData.onBranchChange(() => tui.requestRender());
			const timer = setInterval(() => tui.requestRender(), 30000);

			return {
				dispose() { unsub(); clearInterval(timer); },
				invalidate() { },
				render(width: number): string[] {
					let input = 0, output = 0, cost = 0;
					for (const e of ctx.sessionManager.getBranch()) {
						if (e.type === "message" && e.message.role === "assistant") {
							const m = e.message as AssistantMessage;
							input += m.usage.input;
							output += m.usage.output;
							cost += m.usage.cost.total;
						}
					}

					const usage = ctx.getContextUsage();
					const ctxWindow = usage?.contextWindow ?? 0;
					const pct = usage?.percent ?? 0;
					const remaining = Math.max(0, ctxWindow - (usage?.tokens ?? 0));

					const pctColor = pct > 75 ? "error" : pct > 50 ? "warning" : "success";

					const tokenStats = [
						theme.fg("accent", `⬆${fmt(input)}: ⬇${fmt(output)} `),
						theme.fg("warning", `$${cost.toFixed(2)} `),
						theme.fg(pctColor, `${pct.toFixed(0)}% `),
					].join(" ");

					const elapsed = theme.fg("dim", `⏱${formatElapsed(Date.now() - sessionStart)} `);

					const parts = process.cwd().split("/");
					const short = parts.length > 2 ? parts.slice(-2).join("/") : process.cwd();
					const cwdStr = theme.fg("muted", `⌂ ${short} `);

					const branch = footerData.getGitBranch();
					const branchStr = branch ? theme.fg("accent", `⎇ ${branch} `) : "";

					const thinking = pi.getThinkingLevel();
					const thinkColor = thinking === "high" ? "warning" : thinking === "medium" ? "accent" : thinking === "low" ? "dim" : "muted";
					const modelId = ctx.model?.id || "no-model";
					const modelStr = theme.fg(thinkColor, "◆") + " " + theme.fg("accent", modelId) + " | " + theme.fg(thinkColor, thinking);

					// Plan mode status — read from persisted session entries (same source plan-mode uses)
					type PlanEntry = { type: string; customType?: string; data?: { enabled: boolean; executing?: boolean; todos?: { completed: boolean }[] } };
					const allEntries = ctx.sessionManager.getEntries() as PlanEntry[];
					const planEntry = allEntries.filter((e) => e.type === "custom" && e.customType === "plan-mode").pop();
					const planEnabled = planEntry?.data?.enabled ?? false;
					const planExecuting = planEntry?.data?.executing ?? false;
					const planTodos = planEntry?.data?.todos ?? [];
					let planStr = theme.fg("accent", "BUILD");
					if (planExecuting && planTodos.length > 0) {
						const completed = planTodos.filter((t) => t.completed).length;
						planStr = theme.fg("accent", `📋 ${completed}/${planTodos.length}`);
					} else if (planEnabled) {
						planStr = theme.fg("warning", "PLAN");
					}

					const sep = theme.fg("dim", " | ");
					const leftParts = [modelStr, tokenStats, elapsed, cwdStr];
					if (branchStr) leftParts.push(branchStr);
					if (planStr) leftParts.push(planStr);
					const left = leftParts.join(sep);

					return [truncateToWidth(left, width)];
				},
			};
		});
	});

	pi.on("session_switch", async (event, _ctx) => {
		if (event.reason === "new") {
			sessionStart = Date.now();
		}
	});
}

/**
 * Web Fetch Tool - Fetch web pages and extract content
 */

import { Type } from "@mariozechner/pi-ai";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

export default function (pi: ExtensionAPI) {
	pi.registerTool({
		name: "web-fetch",
		label: "Web Fetch",
		description: "Fetch a web page and extract readable text content",
		parameters: Type.Object({
			url: Type.String({ description: "URL to fetch" }),
			raw: Type.Boolean({ description: "Return raw HTML instead of extracted text", default: false }),
		}),

		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const { url, raw } = params as { url: string; raw: boolean };

			try {
				const res = await fetch(url, {
					method: "GET",
					headers: {
						"User-Agent": "Mozilla/5.0",
						"Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
					},
				});

				if (!res.ok) {
					throw new Error(`HTTP ${res.status}: ${res.statusText}`);
				}

				const html = await res.text();

				if (raw) {
					return {
						content: [{ type: "text", text: html }],
						details: { url, raw: true },
					};
				}

				const text = html
					.replace(/<script[\s\S]*?<\/script>/gi, "")
					.replace(/<style[\s\S]*?<\/style>/gi, "")
					.replace(/<[^>]+>/g, " ")
					.replace(/&nbsp;/g, " ")
					.replace(/&amp;/g, "&")
					.replace(/&lt;/g, "<")
					.replace(/&gt;/g, ">")
					.replace(/&#(\d+);/g, (_, n) => String.fromCharCode(parseInt(n, 10)))
					.replace(/[ \t]+/g, " ")
					.replace(/\n\s*\n/g, "\n")
					.trim();

				return {
					content: [{ type: "text", text: text }],
					details: { url, raw: false },
				};
			} catch (error) {
				return {
					content: [{ type: "text", text: `Error fetching ${url}: ${error instanceof Error ? error.message : 'Unknown error'}` }],
					details: { error: error instanceof Error ? error.message : 'Unknown error' },
				};
			}
		},
	});
}

/**
 * Web Search Tool - Search the web via DuckDuckGo
 */

import { Type } from "@mariozechner/pi-ai";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

export default function (pi: ExtensionAPI) {
	pi.registerTool({
		name: "web-search",
		label: "Web Search",
		description: "Search the web via DuckDuckGo and return results with titles, URLs, and snippets",
		parameters: Type.Object({
			query: Type.String({ description: "Search query terms" }),
			n: Type.Number({ description: "Number of results to return", default: 5, minimum: 1, maximum: 10 }),
		}),

		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const { query, n } = params as { query: string; n: number };

			try {
				const res = await fetch(`https://html.duckduckgo.com/html/?q=${encodeURIComponent(query)}`, {
					method: "GET",
					headers: {
						"User-Agent": "Mozilla/5.0",
					},
				});

				if (!res.ok) {
					throw new Error(`HTTP ${res.status}: ${res.statusText}`);
				}

				const html = await res.text();

				const results = [];
				const blockRe = /<a rel="nofollow" class="result__a" href="([^"]*)"[^>]*>([\s\S]*?)<\/a>[\s\S]*?<a class="result__snippet"[^>]*>([\s\S]*?)<\/a>/g;
				let m;
				while ((m = blockRe.exec(html)) && results.length < n) {
					const url = decodeURIComponent(m[1]
						.replace(/^\/\/duckduckgo\.com\/l\/\?uddg=/, '')
						.replace(/&amp;rut=.*$/, '')
						.replace(/&rut=.*$/, ''));
					const title = m[2].replace(/<[^>]*>/g, '').trim();
					const snippet = m[3].replace(/<[^>]*>/g, '').trim();
					results.push({ title, url, snippet });
				}

				if (!results.length) {
					return {
						content: [{ type: "text", text: "No results found." }],
						details: { query, results: [] },
					};
				}

				const content = results.map((r, i) => `
				${i + 1}. ${r.title}
				   ${r.url}
				   ${r.snippet}
				`).join('\n');

				return {
					content: [{ type: "text", text: content }],
					details: { query, results },
				};
			} catch (error) {
				return {
					content: [{ type: "text", text: `Error searching for "${query}": ${error instanceof Error ? error.message : 'Unknown error'}` }],
					details: { error: error instanceof Error ? error.message : 'Unknown error' },
				};
			}
		},
	});
}

/**
 * Context7 Tool - Search and query documentation
 */

import { Type } from "@mariozechner/pi-ai";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";

async function callContext7(method: string, args: Record<string, any>) {
	const res = await fetch("https://mcp.context7.com/mcp", {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			"Accept": "application/json, text/event-stream"
		},
		body: JSON.stringify({
			jsonrpc: "2.0",
			id: 1,
			method: "tools/call",
			params: {
				name: method,
				arguments: args
			}
		})
	});

	if (!res.ok) {
		throw new Error(`HTTP ${res.status}: ${res.statusText}`);
	}

	const data = await res.json();
	if (data.error) {
		throw new Error(data.error.message);
	}

	if (!data.result || !data.result.content || !data.result.content[0]) {
		throw new Error("Invalid response from Context7 API");
	}

	return data.result.content[0].text;
}

export default function (pi: ExtensionAPI) {
	pi.registerTool({
		name: "context7-search",
		label: "Context7 Search",
		description: "Search for a library and resolve its Context7 library ID for documentation queries.",
		parameters: Type.Object({
			libraryName: Type.String({ description: "The name of the library (e.g. 'react')" }),
			query: Type.String({ description: "Optional query to help find the library. If not provided, libraryName is used.", default: "" }),
		}),

		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const { libraryName, query } = params as { libraryName: string; query?: string };
			const searchQuery = query || libraryName;

			try {
				const text = await callContext7("resolve-library-id", { query: searchQuery, libraryName });
				return {
					content: [{ type: "text", text }],
					details: { libraryName, query: searchQuery },
				};
			} catch (error) {
				return {
					content: [{ type: "text", text: `Error: ${error instanceof Error ? error.message : 'Unknown error'}` }],
					details: { error: error instanceof Error ? error.message : 'Unknown error' },
				};
			}
		},
	});

	pi.registerTool({
		name: "context7-query",
		label: "Context7 Query",
		description: "Query documentation for a specific library using its Context7 library ID.",
		parameters: Type.Object({
			libraryId: Type.String({ description: "The Context7 library ID (e.g. '/websites/react_dev')" }),
			query: Type.String({ description: "Your question or search term for the documentation" }),
		}),

		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			const { libraryId, query } = params as { libraryId: string; query: string };

			try {
				const text = await callContext7("query-docs", { libraryId, query });
				return {
					content: [{ type: "text", text }],
					details: { libraryId, query },
				};
			} catch (error) {
				return {
					content: [{ type: "text", text: `Error: ${error instanceof Error ? error.message : 'Unknown error'}` }],
					details: { error: error instanceof Error ? error.message : 'Unknown error' },
				};
			}
		},
	});
}

